// src/pages/NotFoundPage/index.jsx

import React from 'react';
import { Link } from 'react-router-dom';
import Button from '../../components/UI/Button';
import s from './NotFoundPage.module.css';

const NotFoundPage = () => {
  return (
    <div className={s.container}>
      <h1 className={s.errorCode}>404</h1>
      <h2 className={s.title}>Страница не найдена</h2>
      <p className={s.message}>
        К сожалению, страница, которую вы ищете, не существует. Возможно, вы ввели неправильный адрес или страница была удалена.
      </p>
      <Link to="/">
        <Button type="primary" className={s.homeButton}>
          Вернуться на главную
        </Button>
      </Link>
    </div>
  );
};

export default NotFoundPage;
